/* eslint-disable @typescript-eslint/no-unsafe-argument */
/* eslint-disable @typescript-eslint/no-unsafe-assignment */

/* eslint-disable @typescript-eslint/no-unsafe-member-access */
/* eslint-disable @typescript-eslint/no-unsafe-return */
/* eslint-disable @typescript-eslint/no-unnecessary-condition */
import {
  type ContextSpec,
  EnumGeneration,
  type GeneratorImport,
  getRefInfo,
  isReference,
  isString,
  jsStringLiteralEscape,
  mergeDeep,
  type MockOptions,
  type OpenApiSchemaObject,
} from '@orval/core';

import type { MockDefinition, MockSchema, MockSchemaObject } from '../../types';
import { isFakerVersionV9 } from '../compatible-v9';
import { DEFAULT_FORMAT_MOCK } from '../constants';
import {
  getNullable,
  resolveMockOverride,
  resolveMockValue,
} from '../resolvers';
import { extractArrayItemMock } from './array-item-factory';
import { formatSchemaExampleValue } from '../format-example-value';
import { getMockObject } from './object';

interface GetMockScalarOptions {
  item: MockSchemaObject;
  imports: GeneratorImport[];
  mockOptions?: MockOptions;
  operationId: string;
  isRef?: boolean;
  tags: string[];
  combine?: {
    separator: 'allOf' | 'oneOf' | 'anyOf';
    includedProperties: string[];
  };
  context: ContextSpec;
  // This is used to prevent recursion when combining schemas
  // When an element is added to the array, it means on this iteration, we've already seen this property
  existingReferencedProperties: string[];
  // Tracks the current contiguous `allOf` composition to break cyclic
  // inheritance; threaded through to `combineSchemasMock`.
  // See `existingReferencedAllOfRefs` docs in getters/combine.ts.
  existingReferencedAllOfRefs?: string[];
  splitMockImplementations: string[];
  // This is used to add the overrideResponse to the object
  allowOverride?: boolean;
}

export function getMockScalar({
  item,
  imports,
  mockOptions,
  operationId,
  tags,
  combine,
  context,
  existingReferencedProperties,
  existingReferencedAllOfRefs = [],
  splitMockImplementations,
  allowOverride = false,
}: GetMockScalarOptions): MockDefinition {
  const safeMockOptions: MockOptions = mockOptions ?? {};
  const nonNullableOption = safeMockOptions.nonNullable;
  // Add the property to the existing properties to validate on object recursion
  if (item.isRef) {
    existingReferencedProperties = [...existingReferencedProperties, item.name];
  }

  const operationProperty = resolveMockOverride(
    safeMockOptions.operations?.[operationId]?.properties,
    item,
    nonNullableOption,
  );

  if (operationProperty) {
    return operationProperty;
  }

  let overrideTag: { properties: Record<string, unknown> } = {
    properties: {},
  };
  const sortedTags = Object.entries(safeMockOptions.tags ?? {}).toSorted(
    (a, b) => a[0].localeCompare(b[0], 'en', { numeric: true }),
  );
  for (const [tag, options] of sortedTags) {
    if (!tags.includes(tag)) {
      continue;
    }
    overrideTag = mergeDeep(overrideTag, options);
  }

  const tagProperty = resolveMockOverride(
    overrideTag.properties,
    item,
    nonNullableOption,
  );

  if (tagProperty) {
    return tagProperty;
  }

  const property = resolveMockOverride(
    safeMockOptions.properties,
    item,
    nonNullableOption,
  );

  if (property) {
    return property;
  }

  if (
    context.output.override.mock?.useExamples ||
    safeMockOptions.useExamples
  ) {
    // OAS 3.0 inputs go through @scalar/openapi-parser's upgrade(), which
    // rewrites property-level `example: <value>` into `examples: [<value>]`
    // and deletes the singular field. Fall back to the array form so this
    // option keeps working post-upgrade.
    const propertyExample =
      item.example === undefined
        ? Array.isArray(item.examples) && item.examples.length > 0
          ? item.examples[0]
          : undefined
        : item.example;
    if (propertyExample !== undefined) {
      return {
        value: formatSchemaExampleValue(
          propertyExample,
          item as OpenApiSchemaObject,
          context,
        ),
        imports: [],
        name: item.name,
        overrided: true,
      };
    }
  }

  const formatOverrides = safeMockOptions.format ?? {};
  const ALL_FORMAT: Record<string, string> = {
    ...DEFAULT_FORMAT_MOCK,
    ...Object.fromEntries(
      Object.entries(formatOverrides).filter(
        (entry): entry is [string, string] => typeof entry[1] === 'string',
      ),
    ),
  };

  // Both OpenAPI 3.1 `type: [..., 'null']` and OpenAPI 3.0 `nullable: true`
  // reach here as a null union, because @scalar/openapi-parser upgrades 3.0
  // inputs to 3.1 before mock generation. When this getter wraps the value via
  // `getNullable` it flags the returned MockDefinition with `nullWrapped` so the
  // object property layer does not add a second `arrayElement([..., null])`.
  const isNullable = Array.isArray(item.type) && item.type.includes('null');
  const nullWrapped = isNullable && !nonNullableOption;
  // The @scalar/openapi-parser upgrader rewrites `format: binary` to
  // `contentMediaType: application/octet-stream` when upgrading OAS 3.0 → 3.1;
  // treat both equivalently so the mock emits the binary format value
  // (ArrayBuffer) instead of falling through to the string case.
  const schemaContentMediaType = (item as OpenApiSchemaObject).contentMediaType;
  if (
    !item.format &&
    schemaContentMediaType === 'application/octet-stream' &&
    ALL_FORMAT.binary
  ) {
    return {
      value: getNullable(ALL_FORMAT.binary, isNullable, nonNullableOption),
      imports: [],
      name: item.name,
      overrided: false,
      nullWrapped,
    };
  }
  if (item.format && ALL_FORMAT[item.format]) {
    let value = ALL_FORMAT[item.format];

    const dateFormats = ['date', 'date-time'];
    if (dateFormats.includes(item.format) && context.output.override.useDates) {
      value = `new Date(${value})`;
    }

    return {
      value: getNullable(value, isNullable, nonNullableOption),
      imports: [],
      name: item.name,
      overrided: false,
      nullWrapped,
    };
  }

  const type = getItemType(item);
  const isFakerV9 =
    !!context.output.packageJson &&
    isFakerVersionV9(context.output.packageJson);

  switch (type) {
    case 'number':
    case 'integer': {
      const intFunction =
        context.output.override.useBigInt &&
        (item.format === 'int64' || item.format === 'uint64')
          ? 'bigInt'
          : 'int';
      // Handle exclusiveMinimum/exclusiveMaximum for both OpenAPI 3.0 (boolean) and 3.1 (number).
      // OpenAPI 3.0: booleans indicating whether minimum/maximum is exclusive — use minimum/maximum as the bound.
      // OpenAPI 3.1: numbers representing the exclusive boundary value — use directly.
      const numMin = (
        typeof item.exclusiveMinimum === 'number'
          ? item.exclusiveMinimum
          : (item.minimum ?? safeMockOptions.numberMin)
      ) as number | undefined;
      const numMax = (
        typeof item.exclusiveMaximum === 'number'
          ? item.exclusiveMaximum
          : (item.maximum ?? safeMockOptions.numberMax)
      ) as number | undefined;
      const intParts: string[] = [];
      if (numMin !== undefined) intParts.push(`min: ${numMin}`);
      if (numMax !== undefined) intParts.push(`max: ${numMax}`);
      if (isFakerV9 && item.multipleOf !== undefined)
        intParts.push(`multipleOf: ${item.multipleOf}`);
      let value = getNullable(
        `faker.number.${intFunction}(${intParts.length > 0 ? `{${intParts.join(', ')}}` : ''})`,
        isNullable,
        nonNullableOption,
      );
      if (type === 'number') {
        const floatParts: string[] = [];
        if (numMin !== undefined) floatParts.push(`min: ${numMin}`);
        if (numMax !== undefined) floatParts.push(`max: ${numMax}`);
        if (isFakerV9 && item.multipleOf !== undefined) {
          floatParts.push(`multipleOf: ${item.multipleOf}`);
        } else if (safeMockOptions.fractionDigits !== undefined) {
          floatParts.push(`fractionDigits: ${safeMockOptions.fractionDigits}`);
        }
        value = getNullable(
          `faker.number.float(${floatParts.length > 0 ? `{${floatParts.join(', ')}}` : ''})`,
          isNullable,
          nonNullableOption,
        );
      }
      const numberImports: GeneratorImport[] = [];

      if (item.enum) {
        value = getEnum(
          item,
          numberImports,
          context,
          existingReferencedProperties,
          'number',
        );
      } else if ('const' in item) {
        value = JSON.stringify(item.const);
      }

      return {
        value,
        enums: item.enum,
        imports: numberImports,
        name: item.name,
        // `item.enum` / `const` reassign `value` after `getNullable`, discarding
        // the wrap — so only the plain numeric path is actually null-wrapped.
        nullWrapped: nullWrapped && !item.enum && !('const' in item),
      };
    }

    case 'boolean': {
      let value = 'faker.datatype.boolean()';
      const booleanImports: GeneratorImport[] = [];
      if (item.enum) {
        value = getEnum(
          item,
          booleanImports,
          context,
          existingReferencedProperties,
          'boolean',
        );
      } else if ('const' in item) {
        value = JSON.stringify(item.const);
      }
      return {
        value,
        enums: item.enum,
        imports: booleanImports,
        name: item.name,
      };
    }

    case 'array': {
      if (!item.items) {
        return { value: '[]', imports: [], name: item.name };
      }

      const itemsRef = extractItemsRef(item.items);
      if (
        itemsRef &&
        existingReferencedProperties.includes(
          getRefInfo(itemsRef, context).name,
        )
      ) {
        return { value: '[]', imports: [], name: item.name };
      }

      // If `items` is a single-element `allOf`/`oneOf`/`anyOf` wrapping a
      // `$ref`, treat it as a direct `$ref`. This avoids double-wrapping when
      // the inner schema is an enum array (whose `getEnum` already emits
      // `faker.helpers.arrayElements(...)`) and keeps recursion semantics in
      // line with direct-$ref items.
      const resolvedItems =
        itemsRef && !('$ref' in item.items) ? { $ref: itemsRef } : item.items;

      const {
        value,
        enums,
        imports: resolvedImports,
      } = resolveMockValue({
        schema: {
          ...resolvedItems,
          name: item.name,
          parentName: item.parentName,
          path: item.path ? `${item.path}.[]` : '#.[]',
        },
        combine,
        mockOptions,
        operationId,
        tags,
        context,
        imports,
        existingReferencedProperties,
        existingReferencedAllOfRefs,
        splitMockImplementations,
      });

      if (enums) {
        return {
          value,
          imports: resolvedImports,
          name: item.name,
        };
      }

      let mapValue = value;

      const extractedItemCall = extractArrayItemMock({
        items: resolvedItems,
        propertyName: item.name,
        parentName: item.parentName,
        operationId,
        tags,
        mapValue,
        context,
        splitMockImplementations,
        imports: resolvedImports,
      });
      if (extractedItemCall) {
        mapValue = extractedItemCall;
      }

      if (
        combine &&
        !value.startsWith('faker') &&
        !value.startsWith('{') &&
        !value.startsWith('Array.from')
      ) {
        mapValue = `{${value}}`;
      }

      // Use global defaults for the missing bound only when they do not
      // invert the range; otherwise reuse the explicit schema bound so we
      // never invent values the user did not supply (and never produce
      // min > max). This also avoids relying on faker's internal default
      // upper bound when only `minItems` is specified, which can otherwise
      // produce very large arrays.
      const arrSchemaMin = item.minItems;
      const arrSchemaMax = item.maxItems;
      const arrGlobalMin = safeMockOptions.arrayMin;
      const arrGlobalMax = safeMockOptions.arrayMax;

      let arrMin: number | undefined;
      if (arrSchemaMin !== undefined) {
        arrMin = arrSchemaMin;
      } else if (arrSchemaMax === undefined) {
        arrMin = arrGlobalMin;
      } else if (arrGlobalMin === undefined || arrGlobalMin > arrSchemaMax) {
        arrMin = arrSchemaMax;
      } else {
        arrMin = arrGlobalMin;
      }

      let arrMax: number | undefined;
      if (arrSchemaMax !== undefined) {
        arrMax = arrSchemaMax;
      } else if (arrSchemaMin === undefined) {
        arrMax = arrGlobalMax;
      } else if (arrGlobalMax === undefined || arrGlobalMax < arrSchemaMin) {
        arrMax = arrSchemaMin;
      } else {
        arrMax = arrGlobalMax;
      }

      const arrParts: string[] = [];
      if (arrMin !== undefined) arrParts.push(`min: ${arrMin}`);
      if (arrMax !== undefined) arrParts.push(`max: ${arrMax}`);
      const arrLengthArg =
        arrParts.length > 0 ? `{${arrParts.join(', ')}}` : '';

      return {
        value:
          `Array.from({ length: faker.number.int(` +
          `${arrLengthArg}) ` +
          `}, (_, i) => i + 1).map(() => (${mapValue}))`,
        imports: resolvedImports,
        name: item.name,
      };
    }

    case 'string': {
      // faker.string.alpha's `length: { min, max }` form requires BOTH bounds.
      // When only one side is schema-specified, fall back to the global default
      // for the missing side only if it does not invert the range; otherwise
      // reuse the explicit bound so we never invent values the user did not
      // supply (and never produce min > max).
      const schemaMin = item.minLength;
      const schemaMax = item.maxLength;
      const globalMin = safeMockOptions.stringMin;
      const globalMax = safeMockOptions.stringMax;

      let strMin: number | undefined;
      if (schemaMin !== undefined) {
        strMin = schemaMin;
      } else if (schemaMax === undefined) {
        strMin = globalMin;
      } else if (globalMin === undefined || globalMin > schemaMax) {
        strMin = schemaMax;
      } else {
        strMin = globalMin;
      }

      let strMax: number | undefined;
      if (schemaMax !== undefined) {
        strMax = schemaMax;
      } else if (schemaMin === undefined) {
        strMax = globalMax;
      } else if (globalMax === undefined || globalMax < schemaMin) {
        strMax = schemaMin;
      } else {
        strMax = globalMax;
      }

      // faker.string.alpha's `length: { min, max }` requires both bounds, so
      // only emit a length argument when we have a complete pair. If only one
      // side could be resolved (e.g., no schema bound and only one global is
      // configured) we fall back to faker's own default length.
      const strLenParts: string[] = [];
      if (strMin !== undefined && strMax !== undefined) {
        strLenParts.push(`min: ${strMin}`, `max: ${strMax}`);
      }
      const length =
        strLenParts.length > 0 ? `{length: {${strLenParts.join(', ')}}}` : '';
      let value = `faker.string.alpha(${length})`;
      const stringImports: GeneratorImport[] = [];

      if (item.enum) {
        value = getEnum(
          item,
          stringImports,
          context,
          existingReferencedProperties,
          'string',
        );
      } else if (item.pattern) {
        value = `faker.helpers.fromRegExp(${JSON.stringify(item.pattern)})`;
      } else if ('const' in item) {
        value = JSON.stringify((item as OpenApiSchemaObject).const);
      }

      return {
        value: getNullable(value, isNullable, nonNullableOption),
        enums: item.enum,
        name: item.name,
        imports: stringImports,
        nullWrapped,
      };
    }

    case 'null': {
      return {
        value: 'null',
        imports: [],
        name: item.name,
      };
    }

    default: {
      if (item.enum) {
        const enumImports: GeneratorImport[] = [];
        const value = getEnum(
          item,
          enumImports,
          context,
          existingReferencedProperties,
        );

        return {
          value,
          enums: item.enum,
          imports: enumImports,
          name: item.name,
        };
      }

      return getMockObject({
        item,
        mockOptions,
        operationId,
        tags,
        combine: combine
          ? {
              separator: combine.separator,
              includedProperties: [],
            }
          : undefined,
        context,
        imports,
        existingReferencedProperties,
        existingReferencedAllOfRefs,
        splitMockImplementations,
        allowOverride,
      });
    }
  }
}

// Returns the $ref string from array `items` — either direct ($ref on items
// itself) or wrapped in a single-element allOf/oneOf/anyOf composition.
// Multi-element compositions return undefined to preserve combine semantics.
export function extractItemsRef(items: MockSchema): string | undefined {
  if (isReference(items)) {
    return items.$ref;
  }
  for (const key of ['allOf', 'oneOf', 'anyOf'] as const) {
    const composed = items[key] as MockSchema[] | undefined;
    if (
      Array.isArray(composed) &&
      composed.length === 1 &&
      isReference(composed[0])
    ) {
      return composed[0].$ref;
    }
  }
  return;
}

function getItemType(item: MockSchemaObject) {
  if (Array.isArray(item.type) && item.type.includes('null')) {
    const typesWithoutNull = item.type.filter((x) => x !== 'null');
    const itemType =
      typesWithoutNull.length === 1 ? typesWithoutNull[0] : typesWithoutNull;

    return itemType;
  }

  if (item.type) return item.type;
  if (!item.enum) return;

  const uniqTypes = new Set(item.enum.map((value) => typeof value));
  if (uniqTypes.size > 1) return;

  const type = [...uniqTypes.values()].at(0);
  if (!type) return;
  return ['string', 'number'].includes(type) ? type : undefined;
}

function getEnum(
  item: MockSchemaObject,
  imports: GeneratorImport[],
  context: ContextSpec,
  existingReferencedProperties: string[],
  type?: 'string' | 'number' | 'boolean',
) {
  if (!item.enum) return '';
  const joinedEnumValues = item.enum
    .filter((e) => e !== null) // TODO fix type, e can absolutely be null
    .map((e) =>
      type === 'string' || (type === undefined && isString(e))
        ? `'${jsStringLiteralEscape(e)}'`
        : e,
    )
    .join(',');

  let enumValue = `[${joinedEnumValues}]`;
  if (context.output.override.enumGenerationType === EnumGeneration.ENUM) {
    if (item.isRef || existingReferencedProperties.length === 0) {
      enumValue += ` as ${item.name}${item.name.endsWith('[]') ? '' : '[]'}`;
      imports.push({ name: item.name });
    } else {
      const parentReference = existingReferencedProperties.at(-1);
      if (!parentReference) {
        return '';
      }

      enumValue += ` as ${parentReference}['${item.name}']`;
      if (!item.path?.endsWith('[]')) enumValue += '[]';
      imports.push({
        name: parentReference,
      });
    }
  } else {
    enumValue += ' as const';
  }

  // But if the value is a reference, we can use the object directly via the imports and using Object.values.
  if (item.isRef && type === 'string') {
    enumValue = `Object.values(${item.name})`;
    imports.push({
      name: item.name,
      values: true,
    });
  }

  return item.path?.endsWith('[]')
    ? `faker.helpers.arrayElements(${enumValue})`
    : `faker.helpers.arrayElement(${enumValue})`;
}
